export const cnActivities: Activity[] = [
  {"id":"cn-pressed-flower-cards","title":"Pressed-Flower Greeting Cards","altNames":["Pressed Bloom Cards","Flower Press Notecards","Botanical Cards"],"type":"Craft","place":"Both","ageMin":8,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Flatten gathered blossoms under heavy books, then arrange the papery petals into a card you can actually mail.","materials":["Fresh flat flowers and leaves (pansies, clover, ferns)","Paper towels, several sheets","Heavy books for pressing","Cardstock or folded paper, 1-2 per camper","Glue, applied with a fingertip or small brush","Markers","Scissors"],"materialTags":["Paper towels","Paper","Glue","Markers","Scissors","Paintbrushes"],"steps":["On a nature walk, gather flat flowers, leaves, and grasses, avoiding anything thick or juicy that won't press well.","Lay the flowers in a single layer between paper towels and stack heavy books on top to flatten them.","Wait at least a full day (or use blooms pressed a day ahead) until the petals are dry and papery.","Fold cardstock into a card and lightly plan a layout of the pressed pieces before any glue.","Dab a tiny bit of glue on the back of each piece and press it gently onto the card.","Add a hand-lettered greeting and a thin border of marker or extra leaves around the design."],"notes":"Press a big batch the day before so campers have dry material ready — fresh flowers won't lay flat in one session. Save thick blooms for other crafts; only flat petals press cleanly. For grades 4-6 and up, challenge them to compose a balanced scene (a meadow, a bug, a face) rather than scattering petals randomly.","safety":"Remind campers to gather only from the camp's approved areas and never taste or rub plants on skin, as some can irritate.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Pressed Flower Greeting Card Tutorial","url":"https://www.youtube.com/watch?v=8dipaeiXdbM"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Skip pressing and use pre-pressed flowers as a quick station so cards finish in one sitting.","Laminate or cover the finished design with clear tape to seal fragile petals for a sturdier keepsake.","Older campers design a matched set of four cards with a seasonal theme and a consistent layout."],"subsets":[["Pick small, flat flowers and single leaves.","Avoid stems thicker than a pencil."],["Keep pieces from overlapping while pressing.","Press the petals open, not folded."],[],["Move pieces around before committing to glue.","Leave breathing room around the design."],["Use only a pinhead of glue so petals don't soak.","Press from the center outward."],[]]},
  {"id":"cn-twig-star-ornaments","title":"Twig Star Frames","altNames":["Stick Stars","Twig Pentagons","Yarn-Wrapped Star"],"type":"Craft","place":"Both","ageMin":9,"ageMax":16,"durationMin":45,"groupMin":4,"groupMax":null,"energy":1,"prep":"Low","blurb":"Lash five gathered twigs into a five-pointed star and wrap it in colorful yarn until it shines like a found-wood charm.","materials":["Straight twigs of similar thickness, 5 per camper","Yarn in assorted colors","Scissors","Glue","Small leaves, seeds, or petals to decorate (optional)","Markers (optional)"],"materialTags":["Yarn","Scissors","Glue","Markers"],"steps":["Hunt for five straight twigs of roughly the same thickness, snapping any long ones to even lengths.","Lay the twigs out in a five-pointed star shape so each one crosses two others.","Tie yarn at one joint to start, then wrap the yarn in a figure-eight around each crossing to bind it tight.","Move from point to point lashing every joint until the star holds its shape on its own.","Wrap remaining yarn around the twigs themselves to add color, switching shades for stripes.","Tie a loop at one point to hang it, and tuck a leaf or seed into the wrapping as an accent."],"notes":"Lashing the joints firmly is the make-or-break step, so demo a tight figure-eight before campers start. Twigs that are too green bend instead of holding — drier sticks work best. Pair younger campers with a buddy to hold the star steady while they wrap.","safety":"Check twig ends for sharp broken points and have campers snap or blunt them before lashing.","ages":["g13","g46","g79","g1012"],"rating":0,"media":[{"title":"DIY Twig Star Ornament","url":"https://www.youtube.com/watch?v=yVL181p3OvY"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Make a triangle or square with fewer twigs for a faster younger-camper version.","Weave yarn across the open center like a god's-eye web for a fuller star.","Older campers build a large team star from long branches to hang as a cabin sign."],"subsets":[["Aim for twigs about as long as your forearm.","Pick ones that snap cleanly, not bendy green ones."],["Overlap the ends so each crossing has two sticks.","Adjust until the five points look even."],["Pull the first knot snug.","Cross the yarn over and under each joint."],[],[],[]]},
  {"id":"cn-nature-collage-faces","title":"Nature Collage Faces","altNames":["Leaf People","Found-Object Portraits","Forest Faces"],"type":"Craft","place":"Both","ageMin":6,"ageMax":14,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Turn leaves, petals, seeds, and grass into a silly or fierce face glued onto paper, with bark for hair and berries for eyes.","materials":["Paper or cardboard backing, 1 per camper","Assorted leaves, petals, grass, seeds, and small twigs","Glue","Markers","Scissors","A flat tray or bag to collect materials"],"materialTags":["Paper","Cardboard","Glue","Markers","Scissors"],"steps":["Collect a varied handful of nature bits: big leaves, small petals, grass blades, seeds, and a few twigs.","Sketch a faint oval or circle on the backing as the face outline.","Lay out the pieces to plan features first: leaves for ears, grass for hair, seeds for eyes, a petal mouth.","Glue the largest background pieces down first, then build the features on top.","Add small details with marker or tiny seeds, like freckles, eyebrows, or a smile.","Give the character a name and a personality, then let the glue dry flat."],"notes":"The planning-before-gluing step keeps faces from turning into a blob, so have campers arrange the whole face dry first. Encourage exaggeration — wild grass hair and oversized leaf ears read better than tiny tidy features. Great as a quick filler that scales to any group size.","safety":"Tell campers not to put seeds, berries, or any plant pieces near their mouths, since many are not safe to eat.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Animal Face Out of a Fall Leaf","url":"https://www.youtube.com/watch?v=CJfvhh2OFp0"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Make an animal face instead of a human one, matching materials to the creature.","Work as a pair on one giant face using a big sheet of cardboard.","Older campers create an emotion portrait where the materials express a mood (spiky for angry, soft for calm)."],"subsets":[["Grab a mix of sizes and textures.","Look for naturally face-like shapes."],[],["Try the layout two or three ways before gluing.","Step back to check it reads as a face."],["Hold big pieces a few seconds so glue grabs.","Work from the bottom layer up."],[],[]]},
  {"id":"cn-leaf-print-banners","title":"Leaf-Print Paint Banners","altNames":["Leaf Stamping","Painted Leaf Prints","Botanical Printmaking"],"type":"Craft","place":"Both","ageMin":7,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Brush paint onto the veiny back of a leaf and press it down to stamp a perfect leaf ghost onto a paper banner.","materials":["Fresh leaves with strong veins, several per camper","Paint, washable, assorted colors","Paintbrushes","Paper, large sheets or a long banner strip","Paper towels","Scissors","Yarn (to hang a banner, optional)"],"materialTags":["Paint","Paintbrushes","Paper","Paper towels","Scissors","Yarn"],"steps":["Collect leaves with deep veins and interesting shapes, keeping a mix of sizes.","Lay a leaf vein-side up on a paper towel and brush a thin, even coat of paint across it.","Carefully flip the painted leaf onto the paper and press all over with a clean fingertip, especially the edges.","Peel the leaf straight up to reveal a detailed vein print, then re-ink and repeat in new spots and colors.","Overlap and layer prints in different shades to fill the banner.","Once dry, trim the banner and string yarn through the top to hang it, or add a painted title."],"notes":"A thin coat of paint captures veins; a thick coat blots into a blob, so demo the right amount. The textured back of the leaf prints far better than the smooth front. For grades 4-6 and up, push them to plan a repeating pattern or a color gradient across a long shared banner.","safety":"Use washable paint and cover the table, and have a wipe-station ready so painted hands don't transfer to clothes.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Leaf Stamping & Painting for Kids","url":"https://www.youtube.com/watch?v=gvClzQxU_Ac"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Press leaf prints onto folded paper to make matching greeting cards.","Make a single hero print of one big leaf, framed, instead of a busy banner.","Older campers identify the trees their leaves came from and label each print on a botanical study sheet."],"subsets":[["Pick leaves that lie flat, not curled.","Strong veins print the best detail."],["Paint the bumpy underside, not the smooth top.","Keep the coat thin and even."],["Press the edges and stem firmly.","Don't slide the leaf or it smears."],["Lift straight up, not sideways.","Add a new color before re-pressing."],[],[]]},
  {"id":"cn-pebble-stacking-creatures","title":"Pebble Stack Creatures","altNames":["Stacked Rock Animals","Glued Cairn Critters","Pebble Pals"],"type":"Craft","place":"Both","ageMin":7,"ageMax":14,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Glue smooth stones into a wobbly stacked critter, then paint on eyes, spots, and a grin to bring your pet rock-tower to life.","materials":["Smooth flat pebbles, sorted by size, several per camper","Glue","Paint, washable, and fine brushes","Paintbrushes","Small twigs, seeds, or leaves for limbs and ears","Cardboard base squares, 1 per camper","Paper towels"],"materialTags":["Glue","Paint","Paintbrushes","Cardboard","Paper towels"],"steps":["Sort gathered pebbles from largest to smallest and pick a stack that balances, biggest on the bottom.","Dry-stack the pebbles into a creature shape to test the balance before any glue.","Glue the stack together one stone at a time onto a cardboard base, letting each joint grab before adding the next.","Glue on small twigs for legs or arms and a seed or leaf for ears, a tail, or a nose.","Once the glue holds, paint eyes, a mouth, spots, and details onto the stones.","Name your creature and let everything dry fully before moving it."],"notes":"Sorting by size first makes a stack that actually stands; let glue set between stones or the tower topples. Cardboard bases let creatures be moved without collapse. For younger campers, keep stacks to two or three stones; older ones can attempt taller, leaning towers.","safety":"Keep stones away from the edge of the table so a tipping stack can't drop on toes, and supervise glue near eyes.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Craft Corner: Rock Animals","url":"https://www.youtube.com/watch?v=TtpGHOfsCfU"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Make a flat creature laid on the cardboard instead of a stack for the youngest campers.","Build a whole family of small pebble pals that live together on one base.","Older campers engineer a deliberately leaning or arched stack and explain how the balance holds."],"subsets":[["Lay pebbles out in a size line.","Pick wide, flat ones for the base."],["Stack without glue first.","Wiggle it to find the steady arrangement."],["Glue one stone, count to twenty, then the next.","Press gently so glue spreads at the joint."],[],[],[]]},
  {"id":"cn-seed-bead-mosaic-medallions","title":"Seed Mosaic Medallions","altNames":["Seed Art Discs","Dried-Seed Mosaics","Grain Mosaic Coasters"],"type":"Craft","place":"Inside","ageMin":8,"ageMax":16,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Glue dried beans, seeds, and small pebbles into a tight mosaic pattern on a cardboard disc, like a tiny earthy stained-glass medallion.","materials":["Assorted dried seeds, beans, and split peas (camp pantry)","Small pebbles and seeds gathered outside","Cardboard circles, 1 per camper","Glue","Pencil","Markers","Paper towels"],"materialTags":["Glue","Cardboard","Markers","Paper towels"],"steps":["Cut or hand out a cardboard circle as the medallion base.","Draw a simple design on the disc with pencil, dividing it into sections like a stained-glass window.","Sort the seeds and pebbles by color and size into little piles.","Spread glue inside one section at a time and press seeds in close together to fill it with no gaps.","Work section by section, switching seed types to color each area differently.","Let the medallion dry flat, then add a marker border or punch a hole and add a hanging loop."],"notes":"Working one section at a time keeps glue from drying before seeds land, and packing seeds tightly is what makes it look like a real mosaic. A simple bold design beats a fussy one. For grades 4-6 and up, challenge them to plan a symmetrical or radial pattern and grade the tightness of their tiling.","safety":"Remind campers the dried beans and seeds are craft supplies, not snacks, and not to put any in their mouths.","ages":["g13","g46","g79","g1012"],"rating":0,"media":[{"title":"Beans & Seed Mosaic Art for Kids","url":"https://www.youtube.com/watch?v=1zX8ITBqVo4"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Make a free-form sun or animal shape instead of a sectioned disc.","Press seeds into a thin layer of glue spread over the whole disc for an all-over texture.","Older campers create a true radial mandala with mirrored sections in matching seed colors."],"subsets":[[],["Keep the design bold with big sections.","Fewer, larger shapes fill faster."],["Group seeds by color so each is easy to grab.","Set the piles within reach."],["Glue only the section you'll fill right now.","Push seeds edge to edge with no gaps."],[],[]]},
  {"id":"cn-grass-brush-painting","title":"Grass & Pine-Needle Brushes","altNames":["Nature Paintbrushes","Found-Object Brushes","Grass Bundle Painting"],"type":"Craft","place":"Outside","ageMin":6,"ageMax":14,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Bundle grass, pine needles, leaves, and feathers onto a stick to build wild homemade paintbrushes, then test the marks each one makes.","materials":["Sturdy twigs or sticks, 1-2 per camper","Bundles of grass, pine needles, leaves, small fronds","Yarn or rubber bands to bind bundles","Paint, washable","Paper, large sheets","Scissors","Paper towels"],"materialTags":["Yarn","Rubber bands","Paint","Paper","Scissors","Paper towels"],"steps":["Gather a stick for a handle and a few different bunches of natural bristles: grass, needles, soft leaves.","Hold a bundle against the end of the stick and bind it on tightly with yarn or a rubber band.","Make two or three different brushes, each with a different natural material.","Dip each brush in paint and test its mark on paper — note which makes lines, dabs, or sweeps.","Use the brushes to paint a picture or an abstract texture study, switching brushes for different effects.","Lay finished paintings flat to dry and clean the brushes or set them aside to compost."],"notes":"This is half craft, half experiment — the fun is discovering how each material paints, so build in a testing strip before the real painting. Bind bundles tightly or bristles fall out mid-stroke. Works great outside where mess and gathering are easy.","safety":"Watch for pokey stick ends and pine-needle tips near faces, and use washable paint with a hand-wash station nearby.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"DIY Nature Paint Brushes for Kids","url":"https://www.youtube.com/watch?v=HN0QJ573uF0"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Make one brush each from three materials and compare which paints best in a head-to-head test.","Use the brushes for a big collaborative mural on butcher paper.","Older campers write a short field note describing the stroke each material produces."],"subsets":[["Find a stick that fits your grip.","Gather a few clearly different bristle types."],["Wrap the binding several times around.","Pull it tight and knot it firmly."],[],["Make a few test strokes first.","Notice lines versus dabs versus sweeps."],[],[]]},
  {"id":"cn-stick-loom-leaf-weaving","title":"Stick-Loom Leaf Weaving","altNames":["Twig Loom","Branch Weaving","Nature Loom"],"type":"Craft","place":"Both","ageMin":9,"ageMax":16,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"String a forked branch into a simple loom, then weave grass, leaves, and yarn through the warp into a hanging woodland tapestry.","materials":["A forked or Y-shaped branch, or two crossed sticks, 1 per camper","Yarn for the warp threads","Long grasses, flexible leaves, ferns, flowers","Scissors","Small feathers or seed pods to tuck in (optional)"],"materialTags":["Yarn","Scissors"],"steps":["Find a Y-shaped branch (or lash two sticks into a frame) to be the loom.","Wind yarn back and forth across the opening to create evenly spaced vertical warp threads.","Gather flexible weaving material: long grass, soft leaves, thin vines, and a little extra yarn.","Weave the first strand over-one, under-one across the warp, then push it up to the top.","Weave the next strand the opposite way (under where you went over) and keep alternating, mixing materials.","Tuck in flowers or feathers as accents, tie off the bottom, and add a yarn loop to hang it."],"notes":"Even warp spacing is the secret to easy weaving, so help campers space the strings before they start. Over-under-over is the only rule, but it stalls kids until they catch the rhythm — weave the first two rows alongside them. Flexible green grass weaves better than dry, brittle leaves.","safety":"Check the branch for sharp snapped ends, and keep scissors pointed down when trimming warp threads.","ages":["g13","g46","g79","g1012"],"rating":0,"media":[{"title":"Creating a 'Y' Stick Loom","url":"https://www.youtube.com/watch?v=u9lUuNK2HyI"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Use a rectangular cardboard frame instead of a branch for a more regular loom.","Weave only yarn for a colorful tapestry, adding nature bits as a final accent layer.","Older campers create stripes and color blocks by planning which material goes in each band."],"subsets":[["Look for a sturdy Y with a wide gap.","Two crossed sticks lashed work too."],["Space the warp threads about a finger apart.","Keep the tension even, not too tight."],[],["Say over-under-over out loud as you go.","Slide each row up snug against the last."],["Start the new row on the opposite pattern.","Don't pull so hard the warp bunches."],[]]},
  {"id":"cn-bark-rubbing-journals","title":"Bark & Texture Rubbing Journals","altNames":["Texture Rubbings","Crayon Bark Rubbings","Nature Frottage Book"],"type":"Craft","place":"Outside","ageMin":6,"ageMax":14,"durationMin":30,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Press paper against tree bark, rocks, and leaves and rub a crayon over it to capture every ridge in a little texture-hunt booklet.","materials":["Paper, several sheets per camper","Crayons with wrappers peeled, assorted colors","A clipboard or piece of cardboard backing","Stapler or yarn to bind pages","Markers (optional, for labels)"],"materialTags":["Paper","Crayons","Cardboard","Yarn","Markers"],"steps":["Peel the wrapper off a few crayons so the long side is exposed for rubbing.","On a texture hunt, hold a sheet of paper flat against bark, a rock, a leaf, or a fence.","Rub the side of the crayon back and forth over the paper until the texture appears.","Move to a new texture and a new spot on the paper or a fresh sheet, switching colors.","Label each rubbing with where it came from (oak bark, brick, fern).","Stack the finished sheets and staple or tie them into a little texture journal."],"notes":"Rubbing with the long side of the crayon, not the tip, is what makes textures pop — coach this first. A firm backing behind the paper keeps it from tearing on rough bark. Turning it into a labeled journal gives the wandering a purpose for older kids.","safety":"On the texture hunt, remind campers to stay within the marked boundary and avoid rough surfaces with splinters or insects.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Tree Bark Rubbing Outdoor Activity","url":"https://www.youtube.com/watch?v=_JXO0ICwYcs"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Make a single large collage sheet of overlapping rubbings instead of a booklet.","Layer two textures and two colors over each other on one spot for a richer print.","Older campers make a scavenger checklist of textures to find and rub before time is up."],"subsets":[["Take the paper off the crayon fully.","Use a stubby crayon for big areas."],["Press the paper flat to the surface.","Hold it still with your free hand."],["Rub with the side, not the point.","Use light, even strokes."],[],["Write the source under each rubbing.","Add the date if you like."],[]]},
  {"id":"cn-flower-petal-suncatchers","title":"Petal Press Suncatchers","altNames":["Flower Suncatchers","Petal Window Discs","Pressed-Petal Frames"],"type":"Craft","place":"Both","ageMin":7,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Sandwich bright petals and thin leaves between two sticky frames so the sun glows through every translucent piece.","materials":["Fresh thin petals, small leaves, and grass blades","Masking tape or clear tape","Paper plates or cardboard rings for frames, 2 per camper","Scissors","Hole punch","Yarn for hanging","Markers (optional)"],"materialTags":["Masking tape","Paper plates","Cardboard","Scissors","Yarn","Markers"],"steps":["Gather thin, flat petals and small leaves that light can shine through.","Cut the centers out of two paper plates to make a pair of matching ring frames.","Stretch a piece of clear tape sticky-side-up across one frame opening.","Arrange petals and leaves on the sticky tape, spacing them so light passes between.","Press a second piece of tape on top to seal the petals, then glue or tape the second frame over it to hide the edges.","Punch a hole, thread yarn, and hang it in a sunny window so the petals glow."],"notes":"Thin petals glow; thick ones just look dark, so steer campers toward translucent material. Pressing the petals a few hours ahead keeps them flat, but fresh works in a pinch. The tape-sandwich is fiddly for little hands — pair them up so one holds the frame steady.","safety":"Supervise scissors when cutting frame centers, and keep tape and small petals away from any visiting toddlers' reach.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Flower Petal Suncatcher: Nature Art for Kids","url":"https://www.youtube.com/watch?v=PuRGG0O4px0"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Use a single sticky sheet without a frame for a fast version younger campers can finish quickly.","Arrange petals into a deliberate picture or rainbow gradient instead of scattering them.","Older campers cut a themed frame shape (butterfly, leaf, fish) for the opening."],"subsets":[["Choose petals you can almost see through.","Skip anything thick or fuzzy."],["Trace a cup in the center and cut it out.","Make both frames the same size."],["Tape the corners down so it stays sticky-side-up.","Pull it taut across the opening."],["Don't overlap too much or it goes dark.","Leave little gaps for the light."],[],[]]},
  {"id":"cn-clay-nature-impressions","title":"Air-Clay Nature Impressions","altNames":["Leaf Fossil Tiles","Nature Print Clay","Impression Discs"],"type":"Craft","place":"Both","ageMin":6,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Low","blurb":"Press leaves, ferns, shells, and seed pods into a flattened clay disc to leave behind a crisp fossil-like imprint.","materials":["Air-dry clay or homemade salt dough","Leaves, ferns, seed pods, and shells with texture","Rolling pin or a smooth cup to flatten","A cup or lid to cut a round edge","Paper towels","Yarn (optional, for hanging)","Paint and brushes (optional, for later)"],"materialTags":["Paper towels","Yarn","Paint","Paintbrushes"],"steps":["Roll or press a lump of clay into a flat disc about a finger thick.","Press the rim of a cup into the clay to trim a clean round (or leave it free-form).","Choose a leaf or fern with deep veins and lay it on the clay.","Press the whole leaf firmly and evenly into the surface so every vein registers.","Peel the leaf straight off to reveal a crisp imprint, then poke a hole near the top if you'll hang it.","Set the disc on a paper towel in a warm, dry spot to harden, painting the imprint later once dry."],"notes":"Pressing firmly and evenly is the difference between a faint and a crisp imprint — demo a good press. Veiny leaves and ferns print far better than smooth ones. Discs need a day to dry, so plan painting as a follow-up session, not the same block.","safety":"Have campers wash hands after clay work and avoid touching eyes, and keep any salt-dough out of mouths.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"Nature Prints in Clay for Kids","url":"https://www.youtube.com/watch?v=Np9RCjgkhHM"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Make a thinner disc with a hole for a clay pendant instead of a tile.","Press several small leaves around one disc for a wreath-like border imprint.","Older campers cast a matched set, label each plant, and make a 'fossil collection' display."],"subsets":[["Keep the thickness even all over.","Don't make it so thin it cracks."],[],["Pick a leaf with bumpy veins on the back.","Lay it vein-side down."],["Press with flat fingers across the whole leaf.","Push the edges and stem in too."],["Pull the leaf off in one motion.","Poke the hanging hole before it dries."],[]]},
  {"id":"cn-acorn-seed-mobiles","title":"Acorn & Seed-Pod Mobiles","altNames":["Found-Object Mobile","Seed-Pod Hanging","Nature Dangle"],"type":"Craft","place":"Both","ageMin":8,"ageMax":15,"durationMin":45,"groupMin":3,"groupMax":null,"energy":1,"prep":"Low","blurb":"Tie acorns, seed pods, leaves, and twigs onto strings dangling from a balance stick so the whole thing sways and turns in the breeze.","materials":["A straight stick or twig as the crossbar, 1 per camper","Yarn or string","Acorns, seed pods, dried seeds, small pinecones, leaves","Scissors","Glue (optional, to secure caps)","Markers (optional)"],"materialTags":["Yarn","Scissors","Glue","Markers"],"steps":["Gather a stick for the crossbar and a varied collection of light hanging objects.","Cut several lengths of yarn, varying them so objects hang at different heights.","Tie or glue each natural object onto the bottom of a string.","Tie the top of each string along the crossbar, spacing them out.","Hold the crossbar up by a center string and slide the hanging strings until the bar balances level.","Tie the center hanging loop and hang the mobile where a breeze can spin it."],"notes":"Balancing is the real challenge and the best part — show campers how sliding a string toward the center or end levels the bar. Keep hanging objects light so the stick doesn't bow. For a calmer group, this is a lovely slow, fiddly craft; pair younger kids to hold the bar while they tie.","safety":"Make sure the crossbar has no sharp ends, and hang finished mobiles up high and out of walking paths so no one walks into them.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"DIY Nature Mobile","url":"https://www.youtube.com/watch?v=M8q9phF7458"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Make a flat single-string dangle for the youngest campers instead of a balancing bar.","Theme the objects by color or type (all seed pods, all reds) for a cohesive look.","Older campers add a second crossbar tier below the first for a multi-level balanced mobile."],"subsets":[["Pick a straight, sturdy stick.","Gather light objects so it won't sag."],["Cut strings of a few different lengths.","Leave extra at the top for tying."],["Knot tightly, or glue an acorn cap on.","Tug-test each one before hanging."],[],["Slide strings until the bar sits flat.","Heavier objects move toward the center."],[]]},
  {"id":"cn-sand-bottle-layers","title":"Layered Sand Art Bottles","altNames":["Sand Layer Jars","Colored Sand Bottles","Sand Art Tubes"],"type":"Craft","place":"Both","ageMin":7,"ageMax":15,"durationMin":45,"groupMin":null,"groupMax":null,"energy":1,"prep":"Medium","blurb":"Pour bands of colored sand into a clear bottle, tilting and swirling to build wavy striped layers like a tiny canyon you made yourself.","materials":["Clean clear plastic bottles or cups, 1 per camper","Sand colored with sidewalk chalk or washable marker (pre-made)","Paper for funnels","Spoons or scoops","Skewers or straws to poke patterns","Tape","Scissors"],"materialTags":["Paper","Sidewalk chalk","Straws","Masking tape","Scissors"],"steps":["Pre-color sand by rubbing sidewalk chalk into small batches until each is a different shade.","Roll a sheet of paper into a funnel and set it in the mouth of a clear bottle.","Spoon one color of sand through the funnel to lay down the first band.","Add the next color, tilting the bottle as you pour to make the layer slant and wave.","Gently poke a straw or skewer down along the inside glass to drag the colors into spikes and swirls.","Fill to the top so the sand can't shift, then cap or tape the lid closed."],"notes":"Pre-coloring the sand is the prep that makes this work — do it ahead or run it as a station. Filling all the way to the top stops the layers from collapsing when the bottle moves. Tilting while pouring and poking the edges is what turns flat bands into dramatic waves; show one example first.","safety":"Pour sand over a tray to contain spills and tell campers not to rub sandy hands near their eyes.","ages":["g13","g46","g79"],"rating":0,"media":[{"title":"DIY Colorful Bottle of Sand Art","url":"https://www.youtube.com/watch?v=fcCwR-EzZwU"}],"links":[{"label":"How-to & more ideas","url":"https://www.weareteachers.com/nature-crafts/"}],"variations":["Use a wide clear cup for a faster, easier-to-fill version for younger campers.","Layer plain natural sand with one or two chalk-colored bands for a subtle desert look.","Older campers plan a deliberate landscape (sunset, ocean, mountains) in their layer order."],"subsets":[["Rub chalk into the sand until evenly colored.","Make several distinct shades."],["Tape the funnel so it doesn't slip.","Keep the funnel tip in the bottle neck."],[],["Tilt and rotate the bottle as you pour.","Vary the band thickness."],["Push the straw straight down by the glass.","Drag it up to pull a colored spike."],["Top it off completely so nothing shifts.","Seal the lid with tape."]]},
];
